import {
  getGeo,
  getCountryName,
  isInRegion,
  haversineDistance,
  type Geo,
  type LatLon,
} from 'next/dist/server/request/geo'

// ---------------------------------------------------------------------------
// getGeo
// ---------------------------------------------------------------------------

describe('getGeo', () => {
  it('extracts all Vercel x-vercel-ip-* headers', () => {
    const headers = new Headers({
      'x-vercel-ip-country': 'US',
      'x-vercel-ip-country-region': 'CA',
      'x-vercel-ip-city': 'San Francisco',
      'x-vercel-ip-latitude': '37.7749',
      'x-vercel-ip-longitude': '-122.4194',
      'x-vercel-ip-timezone': 'America/Los_Angeles',
    })

    const geo: Geo = getGeo(headers)

    expect(geo.country).toBe('US')
    expect(geo.region).toBe('CA')
    expect(geo.city).toBe('San Francisco')
    expect(geo.latitude).toBe('37.7749')
    expect(geo.longitude).toBe('-122.4194')
    expect(geo.timezone).toBe('America/Los_Angeles')
  })

  it('falls back to cf-ipcountry when Vercel country header is absent', () => {
    const headers = new Headers({ 'cf-ipcountry': 'DE' })
    expect(getGeo(headers).country).toBe('DE')
  })

  it('prefers x-vercel-ip-country over cf-ipcountry', () => {
    const headers = new Headers({
      'x-vercel-ip-country': 'FR',
      'cf-ipcountry': 'DE',
    })
    expect(getGeo(headers).country).toBe('FR')
  })

  it('accepts a Request object', () => {
    const request = new Request('https://example.com', {
      headers: {
        'x-vercel-ip-country': 'JP',
        'x-vercel-ip-city': 'Tokyo',
      },
    })
    const geo = getGeo(request)
    expect(geo.country).toBe('JP')
    expect(geo.city).toBe('Tokyo')
  })

  it('returns all fields as undefined when no geo headers are present', () => {
    const geo = getGeo(new Headers())
    expect(geo.country).toBeUndefined()
    expect(geo.region).toBeUndefined()
    expect(geo.city).toBeUndefined()
    expect(geo.latitude).toBeUndefined()
    expect(geo.longitude).toBeUndefined()
    expect(geo.timezone).toBeUndefined()
  })

  it('returns only the fields that are present', () => {
    const headers = new Headers({ 'x-vercel-ip-country': 'BR' })
    const geo = getGeo(headers)
    expect(geo.country).toBe('BR')
    expect(geo.city).toBeUndefined()
    expect(geo.latitude).toBeUndefined()
  })
})

// ---------------------------------------------------------------------------
// getCountryName
// ---------------------------------------------------------------------------

describe('getCountryName', () => {
  it('returns the English country name by default', () => {
    expect(getCountryName('US')).toBe('United States')
    expect(getCountryName('GB')).toBe('United Kingdom')
    expect(getCountryName('FR')).toBe('France')
  })

  it('accepts a locale and returns a non-empty string', () => {
    const name = getCountryName('DE', 'de')
    expect(typeof name).toBe('string')
    expect((name as string).length).toBeGreaterThan(0)
  })

  it('is case-insensitive for the country code', () => {
    expect(getCountryName('us')).toBe(getCountryName('US'))
    expect(getCountryName('Fr')).toBe(getCountryName('FR'))
  })

  it('returns a string or undefined for unrecognised codes', () => {
    const result = getCountryName('ZZ')
    // Intl.DisplayNames may return undefined or the code itself for unknown regions
    expect(result === undefined || typeof result === 'string').toBe(true)
  })
})

// ---------------------------------------------------------------------------
// isInRegion
// ---------------------------------------------------------------------------

describe('isInRegion', () => {
  describe('EU', () => {
    it('identifies EU member states', () => {
      expect(isInRegion('FR', 'EU')).toBe(true)
      expect(isInRegion('DE', 'EU')).toBe(true)
      expect(isInRegion('PL', 'EU')).toBe(true)
    })

    it('rejects non-EU countries', () => {
      expect(isInRegion('US', 'EU')).toBe(false)
      expect(isInRegion('NO', 'EU')).toBe(false)
      expect(isInRegion('CH', 'EU')).toBe(false)
    })
  })

  describe('EEA', () => {
    it('includes all EU countries', () => {
      expect(isInRegion('DE', 'EEA')).toBe(true)
      expect(isInRegion('IT', 'EEA')).toBe(true)
    })

    it('includes EEA-only EFTA states (IS, LI, NO)', () => {
      expect(isInRegion('IS', 'EEA')).toBe(true)
      expect(isInRegion('LI', 'EEA')).toBe(true)
      expect(isInRegion('NO', 'EEA')).toBe(true)
    })

    it('rejects countries outside the EEA', () => {
      expect(isInRegion('CH', 'EEA')).toBe(false)
      expect(isInRegion('US', 'EEA')).toBe(false)
    })
  })

  describe('APAC', () => {
    it('identifies APAC countries', () => {
      expect(isInRegion('JP', 'APAC')).toBe(true)
      expect(isInRegion('AU', 'APAC')).toBe(true)
      expect(isInRegion('SG', 'APAC')).toBe(true)
    })

    it('rejects non-APAC countries', () => {
      expect(isInRegion('BR', 'APAC')).toBe(false)
      expect(isInRegion('US', 'APAC')).toBe(false)
    })
  })

  describe('LATAM', () => {
    it('identifies LATAM countries', () => {
      expect(isInRegion('BR', 'LATAM')).toBe(true)
      expect(isInRegion('MX', 'LATAM')).toBe(true)
      expect(isInRegion('AR', 'LATAM')).toBe(true)
    })

    it('rejects non-LATAM countries', () => {
      expect(isInRegion('US', 'LATAM')).toBe(false)
      expect(isInRegion('DE', 'LATAM')).toBe(false)
    })
  })

  describe('MENA', () => {
    it('identifies MENA countries', () => {
      expect(isInRegion('SA', 'MENA')).toBe(true)
      expect(isInRegion('EG', 'MENA')).toBe(true)
      expect(isInRegion('TR', 'MENA')).toBe(true)
    })

    it('rejects non-MENA countries', () => {
      expect(isInRegion('DE', 'MENA')).toBe(false)
      expect(isInRegion('US', 'MENA')).toBe(false)
    })
  })

  describe('NA', () => {
    it('includes CA, MX, US', () => {
      expect(isInRegion('CA', 'NA')).toBe(true)
      expect(isInRegion('MX', 'NA')).toBe(true)
      expect(isInRegion('US', 'NA')).toBe(true)
    })

    it('rejects countries outside NA', () => {
      expect(isInRegion('BR', 'NA')).toBe(false)
      expect(isInRegion('DE', 'NA')).toBe(false)
    })
  })

  describe('AFRICA', () => {
    it('identifies African countries', () => {
      expect(isInRegion('ZA', 'AFRICA')).toBe(true)
      expect(isInRegion('NG', 'AFRICA')).toBe(true)
      expect(isInRegion('KE', 'AFRICA')).toBe(true)
    })

    it('rejects non-African countries', () => {
      expect(isInRegion('FR', 'AFRICA')).toBe(false)
      expect(isInRegion('US', 'AFRICA')).toBe(false)
    })
  })

  describe('CARIBBEAN', () => {
    it('identifies Caribbean countries', () => {
      expect(isInRegion('JM', 'CARIBBEAN')).toBe(true)
      expect(isInRegion('BB', 'CARIBBEAN')).toBe(true)
      expect(isInRegion('TT', 'CARIBBEAN')).toBe(true)
    })

    it('rejects non-Caribbean countries', () => {
      expect(isInRegion('US', 'CARIBBEAN')).toBe(false)
      expect(isInRegion('MX', 'CARIBBEAN')).toBe(false)
    })
  })

  it('is case-insensitive for the country code', () => {
    expect(isInRegion('fr', 'EU')).toBe(true)
    expect(isInRegion('FR', 'EU')).toBe(true)
    expect(isInRegion('jp', 'APAC')).toBe(true)
  })
})

// ---------------------------------------------------------------------------
// haversineDistance
// ---------------------------------------------------------------------------

describe('haversineDistance', () => {
  const london: LatLon = { lat: 51.5074, lon: -0.1278 }
  const paris: LatLon = { lat: 48.8566, lon: 2.3522 }
  const newYork: LatLon = { lat: 40.7128, lon: -74.006 }
  const sydney: LatLon = { lat: -33.8688, lon: 151.2093 }

  it('returns distance in kilometres by default', () => {
